type User struct {
	ID       string `json:"id"`
	Username string `json:"username"`
	Role     string `json:"role"` // admin, moderator, user
}

type Command struct {
	Action  string   `json:"action"`
	Target  string   `json:"target"`
	Items   []string `json:"items"`
	Kick    bool     `json:"kick"`
	Ban     bool     `json:"ban"`
	Give    bool     `json:"give"`
}

func validateUser(user *User) error {
	if user.Role == "" || !isValidRole(user.Role) {
		return fmt.Errorf("invalid role: %s", user.Role)
	}
	return nil
}

func isValidRole(role string) bool {
	switch role {
	case "admin", "moderator":
		return true
	default:
		return false
	}
}

func handleChatMessage(w http.ResponseWriter, r *http.Request) {
	var chatData map[string]interface{}
	err := json.NewDecoder(r.Body).Decode(&chatData)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	userID := r.Header.Get("X-User-ID")
	if userID == "" {
		http.Error(w, "missing user ID", http.StatusUnauthorized)
		return
	}

	var user User
	err = json.Unmarshal([]byte(r.Header.Get("X-User")), &user)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	if err := validateUser(&user); err != nil {
		http.Error(w, err.Error(), http.StatusForbidden)
		return
	}

	var command Command
	err = json.Unmarshal([]byte(r.Header.Get("X-Command")), &command)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	switch command.Action {
	case "/kick":
		kickUser(userID, command.Target)
	case "/ban":
		banUser(userID, command.Target)
	case "/giveitems":
		giveItems(userID, command.Items)
	default:
		http.Error(w, "unknown command", http.StatusNotFound)
	}
}

